// Analyze content and determine cross-platform strategy
const linkedinPosts = $input.first().json;
const instagramPosts = $input.all()[1].json;

// Find content that hasn't been cross-posted
const linkedinContent = linkedinPosts.elements?.map(post => ({
  id: post.id,
  content: post.specificContent?.['com.linkedin.ugc.ShareContent']?.shareCommentary?.text || '',
  timestamp: post.created.time,
  platform: 'linkedin'
})) || [];

const instagramContent = instagramPosts.data?.map(post => ({
  id: post.id,
  content: post.caption || '',
  timestamp: post.timestamp,
  platform: 'instagram'
})) || [];

// Find content suitable for cross-posting
const crossPostCandidates = [];

// LinkedIn to Instagram candidates
linkedinContent.forEach(post => {
  if (post.content.length > 50 && post.content.length < 2200) {
    // Instagram caption limit is 2200 characters
    crossPostCandidates.push({
      ...post,
      targetPlatform: 'instagram',
      optimizedContent: optimizeForInstagram(post.content)
    });
  }
});

// Instagram to LinkedIn candidates
instagramContent.forEach(post => {
  if (post.content.length > 100) {
    // LinkedIn prefers longer, more professional content
    crossPostCandidates.push({
      ...post,
      targetPlatform: 'linkedin',
      optimizedContent: optimizeForLinkedIn(post.content)
    });
  }
});

function optimizeForInstagram(content) {
  // Remove LinkedIn-specific formatting
  let optimized = content
    .replace(/\[\d+\]/g, '') // Remove citation numbers
    .replace(/https?:\/\/[^\s]+/g, '') // Remove URLs
    .trim();

  // Add relevant hashtags
  const hashtags = generateInstagramHashtags(optimized);
  return `${optimized}\n\n${hashtags}`;
}

function optimizeForLinkedIn(content) {
  // Remove Instagram hashtags and emojis
  let optimized = content
    .replace(/#[\w]+/g, '') // Remove hashtags
    .replace(/[\u{1F600}-\u{1F64F}]|[\u{1F300}-\u{1F5FF}]|[\u{1F680}-\u{1F6FF}]|[\u{1F1E0}-\u{1F1FF}]|[\u{2600}-\u{26FF}]|[\u{2700}-\u{27BF}]/gu, '') // Remove emojis
    .trim();

  // Add professional context
  return `📱 Originally shared on Instagram:\n\n${optimized}\n\n#CrossPlatform #SocialMedia #DigitalMarketing`;
}

function generateInstagramHashtags(content) {
  const hashtagCategories = {
    business: ['#business', '#entrepreneur', '#startup', '#marketing'],
    tech: ['#technology', '#innovation', '#digital', '#ai'],
    lifestyle: ['#lifestyle', '#motivation', '#success', '#growth']
  };

  const keywords = content.toLowerCase().split(' ').filter(word => word.length > 3);
  let relevantHashtags = [];

  keywords.forEach(keyword => {
    if (keyword.includes('business') || keyword.includes('entrepreneur')) {
      relevantHashtags.push(...hashtagCategories.business);
    }
    if (keyword.includes('tech') || keyword.includes('digital')) {
      relevantHashtags.push(...hashtagCategories.tech);
    }
  });

  return [...new Set(relevantHashtags)].slice(0, 15).join(' ');
}

return [{ json: { crossPostCandidates } }];

// Filter candidates for LinkedIn to Instagram
const candidates = $input.first().json.crossPostCandidates;
const linkedinToInstagram = candidates.filter(c => c.targetPlatform === 'instagram');

return [{ json: { linkedinToInstagram } }];

// Filter candidates for Instagram to LinkedIn
const candidates = $input.first().json.crossPostCandidates;
const instagramToLinkedin = candidates.filter(c => c.targetPlatform === 'linkedin');

return [{ json: { instagramToLinkedin } }];

// Generate cross-platform sync report
const linkedinToInstagram = $input.first().json;
const instagramToLinkedin = $input.all()[1].json;

const report = {
  timestamp: new Date().toISOString(),
  syncSummary: {
    linkedinToInstagram: linkedinToInstagram.length,
    instagramToLinkedin: instagramToLinkedin.length,
    totalCrossPosts: linkedinToInstagram.length + instagramToLinkedin.length
  },
  recommendations: generateSyncRecommendations(linkedinToInstagram, instagramToLinkedin)
};

function generateSyncRecommendations(linkedinToInstagram, instagramToLinkedin) {
  const recommendations = [];

  if (linkedinToInstagram.length === 0) {
    recommendations.push('Consider creating more LinkedIn content suitable for Instagram');
  }

  if (instagramToLinkedin.length === 0) {
    recommendations.push('Consider creating more Instagram content suitable for LinkedIn');
  }

  if (linkedinToInstagram.length + instagramToLinkedin.length < 5) {
    recommendations.push('Increase content creation frequency for better cross-platform reach');
  }

  return recommendations;
}

return [{ json: report }];

